  heroSub: { fontSize: 13, letterSpacing: "0.25em", color: "#fff", marginBottom: 32 },
  credits: { position: "fixed", bottom: 0, left: 0, right: 0, zIndex: 30, display: "flex", justifyContent: "space-around", padding: "18px 36px 22px", background: "linear-gradient(to top,rgba(0,0,0,.9),transparent)" },
  authBox: { width: "100%", maxWidth: 360, position: "relative", zIndex: 20, display: "flex", flexDirection: "column", gap: 12 },
  authToggle: { display: "flex", border: "1px solid #1a1a1a", overflow: "hidden", marginBottom: 8 },
